						+ '<div style="width:28px;height:28px;border-radius:8px;background:#fef2f2;display:flex;align-items:center;justify-content:center;flex-shrink:0;font-size:13px;font-weight:800;color:#dc2626;">' + (i+1) + '</div>'
						+ '<div style="flex:1;">'
